import SwiftUI

class SocialCrossPostingViewModel: ObservableObject {
    let platforms = ["Twitter", "Facebook", "Instagram"]
    @Published var connectedPlatforms: Set<String> = []
    @Published var selectedForPost: Set<String> = []
    @Published var postText: String = ""
    @Published var lastPostResult: String?
    @Published var platformPendingConnect: String?

    func connect(platform: String) { platformPendingConnect = platform }

    func confirmConnect(platform: String) {
        connectedPlatforms.insert(platform)
        platformPendingConnect = nil
    }

    func toggleSelected(platform: String) {
        guard connectedPlatforms.contains(platform) else { return }
        if selectedForPost.contains(platform) { selectedForPost.remove(platform) }
        else { selectedForPost.insert(platform) }
    }

    func post() {
        guard !postText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty,
              !selectedForPost.isEmpty else { return }
        let list = selectedForPost.sorted().joined(separator: ", ")
        lastPostResult = "Posted to " + list + " (demo)"
    }
}

struct SocialCrossPostingView: View {
    @StateObject private var viewModel = SocialCrossPostingViewModel()

    var body: some View {
        VStack(alignment: .leading, spacing: 16) {
            Text("Real posting requires API setup per platform")
                .font(.caption)
                .foregroundStyle(.secondary)

            TextField("Post content", text: $viewModel.postText, axis: .vertical)
                .textFieldStyle(.roundedBorder)
                .lineLimit(3...6)

            ForEach(viewModel.platforms, id: \.self) { platform in
                HStack {
                    Text(platform)
                    Spacer()
                    if viewModel.connectedPlatforms.contains(platform) {
                        Text("Connected").font(.caption).foregroundStyle(.secondary)
                        Button { viewModel.toggleSelected(platform: platform) } label: {
                            Image(systemName: viewModel.selectedForPost.contains(platform) ? "checkmark.circle.fill" : "circle")
                        }
                    } else {
                        Text("Not Connected").font(.caption).foregroundStyle(.secondary)
                        Button("Connect") { viewModel.connect(platform: platform) }
                    }
                }
                .padding(.vertical, 4)
            }

            Button("Post") { viewModel.post() }
                .disabled(viewModel.postText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty || viewModel.selectedForPost.isEmpty)
        }
        .padding()
        .alert("Connect", isPresented: Binding(get: { viewModel.platformPendingConnect != nil }, set: { if !$0 { viewModel.platformPendingConnect = nil } })) {
            Button("OK") { if let p = viewModel.platformPendingConnect { viewModel.confirmConnect(platform: p) } }
            Button("Cancel", role: .cancel) { viewModel.platformPendingConnect = nil }
        } message: {
            if let p = viewModel.platformPendingConnect {
                Text("In a full app you would sign in with " + p + " here; this demo saves your choice.")
            }
        }
        .alert("Posted", isPresented: Binding(get: { viewModel.lastPostResult != nil }, set: { if !$0 { viewModel.lastPostResult = nil } })) {
            Button("OK") { viewModel.lastPostResult = nil }
        } message: {
            if let result = viewModel.lastPostResult { Text(result) }
        }
    }
}
